import{_ as f,o as k,c as K,a6 as x,gn as S,go as P,gp as C,gq as V,gr as v,es as D,gs as E,gt as L,gu as w,gv as A,gw as T,gh as B,gx as F,gy as p,gz as N,hs as g,gA as I,gB as O,gC as y,gD as G,gE as H,gF as n,gG as s,gH as i,gI as l,gJ as e,gK as M,gL as m,gM as Q,gN as R,gO as $,gP as j,gQ as q,gR as U,gS as h,gT as c,gU as J,gV as W,gW as X,gX as z,gY as Y,gZ as Z,ey as pp,g_ as sp,g$ as tp,h0 as rp,h1 as ap,h2 as op,h3 as gp,h4 as np,h5 as ip,h6 as lp,h7 as ep,h8 as mp,h9 as hp,ha as _,hb as t,hc as d,hd as u,he as cp,hf as _p,hg as dp,hh as up,hi as bp,hj as fp,hk as kp,hl as Kp,hm as xp,hn as Sp,ho as Pp,hp as Cp,hq as Vp,hr as vp,ht as Dp,hu as Ep,hv as Lp,hw as wp,hx as Ap,eu as Tp,hy as Bp,hA as Fp,hB as Np,hC as Ip,hD as Op,hE as yp,hF as Gp,hG as Hp,hH as Mp,hI as Qp,hJ as Rp,hK as $p,hL as r,hM as jp,hN as qp,hO as b,hP as a,hQ as Up,hR as Jp,hS as Wp,hT as Xp,hU as zp}from"./chunks/framework.UYVGz2W_.js";const gs=JSON.parse('{"title":"ビデオゲームの制作","description":"","frontmatter":{},"headers":[],"relativePath":"ja/videogame/index.md","filePath":"ja/videogame/index.md"}'),Yp={name:"ja/videogame/index.md"};function Zp(ps,o,ss,ts,rs,as){return k(),K("div",null,[...o[0]||(o[0]=[x('<h1 id="ビデオゲームの制作" tabindex="-1">ビデオゲームの制作 <a class="header-anchor" href="#ビデオゲームの制作" aria-label="Permalink to “ビデオゲームの制作”">​</a></h1><p>Kitsuでワークフローを設計し、より多くの人を招待したので、今度は制作を開始します。</p><p>[<strong>新しい制作を作成</strong>]ボタンをクリックします。</p><p><img src="'+S+'" alt="制作を作成"></p><p>制作名を入力し、<strong>タイプ</strong>として<strong>短い</strong>を選択し、制作スタイル（2D、3D）を選択します。</p><p>次に、FPS数、比率、解像度などの技術情報を入力する必要があります。</p><p>これらのデータは、Kitsuがアップロードされたビデオプレビューを再エンコードする際に使用されます。</p><p>次に、制作物の開始日と終了日を定義する必要があります。</p><p><img src="'+P+'" alt="制作物の追加"></p><p>次のパート 3 から 6 で、制作ワークフローを定義できます。</p><p>アセットタスクタイプ (3)、マッピングタスクタイプ (4)、タスクステータス (5)、アセットタイプ (6) を選択する必要があります。</p><p><img src="'+C+'" alt="制作パイプラインの追加"></p><p>::: ヒント 制作ワークフロー**を作成するには、グローバルライブラリからタスクタイプを選択します。</p><p>タスクタイプをいくつか見落としていたことに気づいた場合は、後で作成することができます。</p><p><a href="./../configure-kitsu/#studio-workflow">スタジオワークフロー</a> のセクションを参照してください。 :::</p><p>次に、7と8はオプション部分です。アセット/マップのスプレッドシートをすでに持っている場合は、</p><p><strong>インポートCSV</strong>のセクションを参照してください。</p><p>アセットのインポート</p><p>マップのインポート</p><p><img src="'+V+'" alt="All done"> ボタンですべてを検証します。</p><h2 id="kitsuグローバルページの紹介" tabindex="-1">Kitsuグローバルページの紹介 <a class="header-anchor" href="#kitsuグローバルページの紹介" aria-label="Permalink to “Kitsuグローバルページの紹介”">​</a></h2><p>Kitsuのグローバルアセットページへようこそ。</p><p>見てみましょう。</p><p><img src="'+v+'" alt="グローバルページの紹介"></p><p>上部 (1) には、<strong>グローバルナビゲーション</strong>があり、これはすべての制作ページで常に表示されます。</p><p><strong>左から右へ:</strong></p><h3 id="メインメニュー" tabindex="-1">メインメニュー <a class="header-anchor" href="#メインメニュー" aria-label="Permalink to “メインメニュー”">​</a></h3><p>左上のボタン、Kitsu<img src="'+D+'" alt="メインメニューボタン">（またはお客様のスタジオロゴ）をクリックすると、メインメニューが開きます。</p><p>メインメニューでは、割り当てられたタスク、制作物、グローバルおよびチームスケジュール、ワークフローのカスタマイズページ、およびKitsu設定に直接アクセスできます。</p><p>::: 詳細 メインメニューの詳細 <strong>ワークスペース</strong></p><ul><li>マイタスク：割り当てられたタスク</li><li>マイチェック：あなたの部署に応じて、ステータスが<strong>フィードバックリクエスト</strong>となっているすべてのタスク</li><li>マイプロダクション：プロダクションページの選択に戻ります。</li></ul><p><strong>スタジオ</strong></p><ul><li>プロダクション</li><li>担当者</li><li>タイムシート</li><li>メインスケジュール</li><li>チームスケジュール</li><li>すべてのタスク</li><li>ニュースフィード</li><li>エンティティ検索</li></ul><p><strong>ADMIN</strong></p><ul><li>部署</li><li>タスクの種類</li><li>アセットの種類</li><li>カスタムアクション</li><li>自動化</li><li>3D背景</li><li>ボット</li><li>設定</li><li>ログ</li></ul><p>::: 警告 権限の表示 ワークスペースセクションは、アーティストには表示されない「マイチェック」を除くすべての権限に対して有効になっています。</p><p>アーティスト（およびそれ以上）は、自身の<strong>タイムシート</strong>も表示でき、<strong>エンティティ検索</strong>にもアクセスできます :::</p><h3 id="ナビゲーション" tabindex="-1">ナビゲーション <a class="header-anchor" href="#ナビゲーション" aria-label="Permalink to “ナビゲーション”">​</a></h3><p>メインメニューアイコンの右側にナビゲーションドロップダウンメニューが表示されます。</p><p><img src="'+E+'" alt="グローバルページの表示"></p><p>制作を選択できます。実際の制作名と実際のページ名が常に表示されます。</p><p>ドロップダウンメニューを使用して、制作から制作へと移動できます（複数の制作がある場合）。</p><p>制作を選択すると、次のドロップダウンメニューで、その制作の異なるページを移動することができます。</p><p>::: 詳細 ナビゲーション詳細 最初のセクションは、タスクのトラッキングについてです</p><ul><li>アセット</li><li>マップ</li><li>レベル</li><li>編集（特定のタスクを作成した場合）</li></ul><p>2番目のセクションは、制作の側面についてです</p><ul><li>コンセプト</li><li>ブレークダウン</li><li>プレイリスト</li><li>ニュースフィード</li></ul><p>3番目のセクションは統計情報に関するものです。 レベル統計、 アセットタイプ統計</p><p>4番目のセクションはチーム管理に関するものです。 スケジュール、 ノルマ、 チーム</p><p>5番目のセクションは制作の設定に関するものです。 設定</p><p>::: ヒント アセットページから開始しますが、制作のホームページを他のエンティティに変更することができます（設定ページを参照）。 :::</p><p>::: 警告 チャプターとして追加のナビゲーションレベルが必要だと気づいた場合は、制作タイプを<strong>TV Show</strong>に変更する必要があります。</p><p>逆に、<strong>assets</strong>や<strong>maps</strong>が必要ないことに気づいた場合は、制作タイプを<strong>Only Assets</strong>または<strong>Only Maps</strong>に切り替える必要があります。 :::</p><h3 id="グローバル検索、ニュース、通知、およびドキュメント" tabindex="-1">グローバル検索、ニュース、通知、およびドキュメント <a class="header-anchor" href="#グローバル検索、ニュース、通知、およびドキュメント" aria-label="Permalink to “グローバル検索、ニュース、通知、およびドキュメント”">​</a></h3><p>グローバル検索はナビゲーションドロップダウンメニューの右側にあります。 4つの最初の結果を表示するクイックアクセス検索です。 さらに多くの結果やフィルタリングオプションが必要な場合は、<strong>エンティティ検索</strong>ページを参照してください。</p><p>次のアイコン <img src="'+L+'" alt="ニュース"> は、ニュースとフィードバックページへの直接リンクです。</p><p>アニメーションGIFで新機能のすべてをご覧いただけます。また、Kitsuに追加してほしい次期機能に関するご意見もご投稿いただけます。</p><p>ベルのアイコンは、通知（割り当て、コメント、タグ）を表示します！<a href="../img/getting-started/notification_icon_on.png">通知</a>。未読の通知の数は、ベルのアイコンに表示されます。</p><p>アバターの直前のアイコンは、ドキュメントボタンです。 <img src="'+w+'" alt="ドキュメントボタン"> あなたが今読んでいるドキュメントです！</p><h3 id="個人設定" tabindex="-1">個人設定 <a class="header-anchor" href="#個人設定" aria-label="Permalink to “個人設定”">​</a></h3><p>アバターをクリックすると、メニュー（設定、ドキュメントなど）を開くことができます。</p><p><img src="'+A+'" alt="プロファイル拡大"></p><h2 id="タスクスプレッドシート" tabindex="-1">タスクスプレッドシート <a class="header-anchor" href="#タスクスプレッドシート" aria-label="Permalink to “タスクスプレッドシート”">​</a></h2><h3 id="エンティティスプレッドシート" tabindex="-1">エンティティスプレッドシート <a class="header-anchor" href="#エンティティスプレッドシート" aria-label="Permalink to “エンティティスプレッドシート”">​</a></h3><p>画面の2番目の部分は、すべてのエンティティ（アセット、マップ、レベル、編集）に共通です。これはグローバルなタスクスプレッドシートです。</p><p>ここでは、各タスクのステータス、割り当て、優先度などを確認できます。</p><p>::: ヒント スプレッドシートの最初の行と列のヘッダーは、スクロールしても常にページの一番上に表示されます。</p><p>また、他の列を常に表示しておくために「固定」することもできます。 :::</p><h3 id="フィルター" tabindex="-1">フィルター <a class="header-anchor" href="#フィルター" aria-label="Permalink to “フィルター”">​</a></h3><p>左側の最初の要素はフィルターボックスです。簡単なフィルタリングを行うには、レベルやアセットタイプなど、任意の文字列を入力します。</p><p>より高度なフィルタリングが必要な場合は、フィルタービルダーボタンを使用してください。</p><p><img src="'+T+'" alt="フィルタービルダー"></p><p>すべてのフィルターを保存し、ページとして使用することができます。</p><h3 id="表示の簡素化" tabindex="-1">表示の簡素化 <a class="header-anchor" href="#表示の簡素化" aria-label="Permalink to “表示の簡素化”">​</a></h3><p>画面の右側には、左から右に、アサインメントの表示/非表示、追加カラムの表示/非表示、サムネイルの拡大/縮小を行うためのボタンがあります。 <img src="'+B+'" alt="表示と非表示オプション"></p><h3 id="インポート-エクスポート" tabindex="-1">インポート / エクスポート <a class="header-anchor" href="#インポート-エクスポート" aria-label="Permalink to “インポート / エクスポート”">​</a></h3><p>バッチインポートサムネイル <img src="'+F+'" alt="バッチインポートサムネイル">、最後にインポート <img src="'+p+'" alt="インポートボタン"> またはエクスポート <img src="'+N+'" alt="エクスポートボタン"> データの</p><h3 id="メタデータカラム" tabindex="-1">メタデータカラム <a class="header-anchor" href="#メタデータカラム" aria-label="Permalink to “メタデータカラム”">​</a></h3><p>以下に、カラムの名前があります。<strong>名前</strong>の隣にある(+)をクリックすると、<img src="'+g+'" alt="Add metadata column"> が表示され、新しいメタデータカラムを作成できます。次に、タスクタイプのカラムの名前があります。</p><h3 id="ビューのカスタマイズ" tabindex="-1">ビューのカスタマイズ <a class="header-anchor" href="#ビューのカスタマイズ" aria-label="Permalink to “ビューのカスタマイズ”">​</a></h3><p>画面の一番右側、スクロールバーの隣に、テキストカラムの表示/非表示を切り替えるオプションがあります</p><p><img src="'+I+'" alt="テキストカラムの表示/非表示">。</p><h3 id="ビューの要約" tabindex="-1">ビューの要約 <a class="header-anchor" href="#ビューの要約" aria-label="Permalink to “ビューの要約”">​</a></h3><p>最後の部分（4）は、画面の下部にある、表示されたページの要約です。つまり、ページをフィルタリングすると、要約も更新されます。</p><p>表示されているページのサマリーが表示されます。 表示されているページでフィルタリングを行うと、サマリーも更新されます。 表示されているアセット（またはマップ）の数、見積もり日数の合計、およびすでに費やした日数の合計を確認できます。</p><h2 id="アセットの作成" tabindex="-1">アセットの作成 <a class="header-anchor" href="#アセットの作成" aria-label="Permalink to “アセットの作成”">​</a></h2><h3 id="最初のアセットの作成" tabindex="-1">最初のアセットの作成 <a class="header-anchor" href="#最初のアセットの作成" aria-label="Permalink to “最初のアセットの作成”">​</a></h3><p>ここまでで、本番環境を作成し、Kitsuインターフェースの概要を把握しました。 それでは、最初の1つ目のアセットを作成してみましょう。</p><p>アセットページで、<strong>[アセットを追加]</strong>をクリックします。</p><p><img src="'+O+'" alt="Asset page first time"></p><p>::: 警告 アセットを作成すると、タスクワークフローが適用され、<strong>すべてのタスクがアセットと同時に作成されます</strong>。 :::</p><p>ポップアップウィンドウが開きます。</p><p><strong>アセットタイプ</strong>の選択を求められます（1）。 新しいアセットタイプを追加していない場合、Kitsuは「キャラクター」、「環境」、「エフェクト」、「小道具」などの例を提供します。 まずはキャラクターから始めましょう。</p><p><strong>名前</strong> (2) を付け、アーティストが何をすべきか、またアセットを素早く識別できるようにするための説明を入力します。</p><p>複数のアセットを作成する場合は、<strong>「確認して戻る」</strong>をクリックします。</p><p><img src="'+y+'" alt="アセットの作成"></p><p>アセットの種類を変更して、アセットを追加し続けることができます。</p><p>::: ヒント 「確認して戻る」をクリックするたびに、新しく作成したアセットが背景に表示されます。 :::</p><p>最後のアセットを追加したら、 「確認」をクリックします。これによりアセットが作成され、ウィンドウが閉じます。</p><p>::: ヒント 「確認して戻る」をクリックし、追加するアセットがもうないことに気づき、「閉じる」をクリックすると、ウィンドウがキャンセルされます。 :::</p><p><img src="'+G+'" alt="グローバルアセットページ"></p><p>また、アセットワークフローで選択されたタスクも同時に作成されます。</p><p>さらに<strong>アセット</strong>を追加する必要がある場合は、<strong>+ アセットの作成</strong>ボタンをクリックします。</p><p>::: 詳細 CSVスプレッドシートファイルからのアセットの作成 アセットのリストがすでにスプレッドシートファイルに用意されているかもしれません。 Kitsuでは、それらをインポートする方法が2つあります。1つ目は、<code>.csv</code>ファイルをインポートし、データを直接Kitsuにコピー＆ペーストする方法です。</p><p>まず、スプレッドシートを<code>.csv</code>ファイルとして保存します。</p><p>次に、Kitsuのアセットページに戻り、<strong>インポート</strong>アイコンをクリックします。 <img src="'+p+'" alt="インポートアイコン"></p><p>ポップアップウィンドウ「<strong>CSVからデータをインポート</strong>」が開きます。<strong>参照</strong>をクリックして、<code>.csv</code>ファイルを選択します。</p><p><img src="'+H+'" alt="CSVファイルのインポート"></p><p>結果を確認するには、<strong>プレビュー</strong>ボタンをクリックします。</p><p>データのプレビューで列の名前を確認し、調整することができます。</p><p>注：<strong>「チャプター」</strong>列は、<strong>「テレビ番組」</strong>制作の場合のみ必須です。</p><p><img src="'+n+'" alt="データのインポート データのコピー＆ペースト"></p><p>すべてが適切であることを確認したら、<strong>「確認」</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべての資産がKitsuにインポートされ、設定に従ってタスクが作成されました。</p><p><img src="'+s+'" alt="インポートデータコピーペーストデータ"> ::::</p><p>:::: 詳細 スプレッドシートファイルのコピー/ペーストによる資産の作成</p><p>スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+i+'" alt="コピーデータのインポート"></p><p>次に、Kitsuのアセットページに戻り、<strong>インポート</strong>アイコンをクリックします <img src="'+p+'" alt="インポートアイコン">。</p><p>ポップアップウィンドウ<strong>CSVからのインポート</strong>が開きますので、<strong>CSVデータの貼り付け</strong>タブをクリックします。</p><p><img src="'+l+'" alt="インポートデータのコピー＆ペーストタブ"></p><p>以前に選択したデータを貼り付け、<strong>[プレビュー]</strong>ボタンで結果を確認できます。</p><p><img src="'+e+'" alt="インポートデータのコピー＆ペーストデータ"></p><p>データのプレビューで列の名前を確認し、調整することができます。</p><p>注：<strong>chapter</strong>（チャプター）の列は、<strong>TV Show</strong>（テレビ番組）制作の場合のみ必須です。</p><p><img src="'+n+'" alt="Import data copy paste data"></p><p>すべて問題なければ、<strong>Confirm</strong>（確認）ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべてのアセットがKitsuにインポートされ、設定に従ってタスクが作成されました。</p><p><img src="'+s+'" alt="インポートデータ コピーペーストデータ"> :::</p><h3 id="アセットの詳細を確認する" tabindex="-1">アセットの詳細を確認する <a class="header-anchor" href="#アセットの詳細を確認する" aria-label="Permalink to “アセットの詳細を確認する”">​</a></h3><p>アセットの詳細を確認するには、その名前をクリックします。</p><p><img src="'+M+'" alt="アセットの詳細"></p><p>新しいページが開き、右側にタスク、アサイン、ステータスニュースフィードの一覧が表示されます。</p><p><img src="'+m+'" alt="アセット詳細ページ"></p><p>各タスクのステータスをクリックすると、コメントパネルが開き、コメントの履歴や異なるバージョンを確認できます。</p><p><img src="'+Q+'" alt="アセット詳細ページ"></p><p>また、<strong>キャスティング</strong>にもアクセスできます。</p><p><img src="'+R+'" alt="アセット詳細キャスティング"></p><p>このアセットに関連付けられた<strong>コンセプト</strong>にもアクセスできます。</p><p><img src="'+$+'" alt="アセット詳細キャスティング"></p><p><strong>スケジュール</strong>は、タスクタイプページのデータを事前に記入していれば利用できます。データがすでに記入されている場合は、ここで直接修正することができます。</p><p><img src="'+j+'" alt="アセット詳細キャスティング"></p><p>さまざまなタスクタイプでアップロードされた<strong>プレビューファイル</strong>、</p><p><img src="'+q+'" alt="アセット詳細のキャスティング"></p><p>そして、このアセットのタスクでタイムシートが記入された場合の<strong>タイムログ</strong>。</p><p><img src="'+U+'" alt="アセット詳細のキャスティング"></p><h2 id="アセットを作成した後にタスクを追加する" tabindex="-1">アセットを作成した後にタスクを追加する <a class="header-anchor" href="#アセットを作成した後にタスクを追加する" aria-label="Permalink to “アセットを作成した後にタスクを追加する”">​</a></h2><p>アセットを作成した後にタスクが欠けていることに気づいた場合でも、追加することができます。</p><p>まず、欠けているタスクタイプがタスクタイプタブの設定ページに追加されていることを確認してください。</p><p>次に、アセットページに戻り、<strong>+ タスクを追加</strong>をクリックします</p><h3 id="アセットを更新する" tabindex="-1">アセットを更新する <a class="header-anchor" href="#アセットを更新する" aria-label="Permalink to “アセットを更新する”">​</a></h3><p>アセットはいつでも更新でき、名前やアセットタイプを変更したり、説明文を修正したり、グローバルページに追加したカスタム情報を追加したりすることができます。</p><p>アセットを編集するには、アセットページに移動し、編集したいアセットの上にカーソルを移動させて、<strong>編集</strong>ボタンをクリックします ！<a href="../img/getting-started/edit_button.png">編集ボタン</a> (1) 行の右側にある</p><p><img src="'+h+'" alt="アセットの編集"></p><p>アセットのメインページの説明を拡張するには、最初の語句 (2) をクリックすると、説明の全文を含むポップアップが開きます。</p><p>アセットを削除するには、FAQ : アセットの削除方法を参照してください。</p><p>::: 詳細 CSV インポートによるアセットの更新 CSV インポートを使用すると、データをすばやく更新することができます。</p><p>アセットの<strong>タイプ</strong>、<strong>割り当て</strong>、タスクの<strong>ステータス</strong>を更新したり、<strong>コメント</strong>を追加したりすることができます。</p><p><strong>既存のデータを更新する</strong>オプションをオンにする必要があります。すると、更新される行が 青くハイライトされます。</p><p><img src="'+c+'" alt="インポートデータ コピー＆ペーストデータ"></p><p>:::</p><p>::: 詳細 スプレッドシートのコピー＆ペーストによるアセットの更新。 ファイル</p><p>スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+i+'" alt="インポート コピーデータ"></p><p>次に、Kitsuのアセットページに戻り、<strong>インポート</strong>アイコンをクリックします <img src="'+p+'" alt="インポートアイコン">。</p><p>ポップアップウィンドウ「<strong>CSVからデータをインポート</strong>」が開きますので、「<strong>CSVデータを貼り付け</strong>」タブをクリックします。</p><p><img src="'+l+'" alt="インポートデータコピーペーストタブ"></p><p>以前に選択したデータを貼り付け、<strong>[プレビュー]</strong> ボタンで結果を確認できます。</p><p><img src="'+e+'" alt="データのコピー＆ペースト"></p><p>データをプレビューして、カラム名を確認し、調整することができます。</p><p>注：<strong>[チャプター]</strong> カラムは、<strong>[テレビ番組]</strong> 制作の場合のみ必須です。</p><p>オプション「<strong>既存データの更新</strong>」をオンにする必要があります。すると、更新される行が 青くハイライトされます。</p><p><img src="'+c+'" alt="データのインポート データのコピー＆ペースト"></p><p>これで、すべてのアセットがKitsuにインポートされ、設定に従ってタスクが作成されました。</p><p><img src="'+s+'" alt="インポートデータコピーペーストデータ"> :::</p><h2 id="コンセプトの作成" tabindex="-1">コンセプトの作成 <a class="header-anchor" href="#コンセプトの作成" aria-label="Permalink to “コンセプトの作成”">​</a></h2><h3 id="コンセプトのアップロード" tabindex="-1">コンセプトのアップロード <a class="header-anchor" href="#コンセプトのアップロード" aria-label="Permalink to “コンセプトのアップロード”">​</a></h3><p><strong>コンセプト</strong>を作成するには、ナビゲーションメニューから<strong>コンセプト</strong>ページに移動します。</p><p><img src="'+J+'" alt="コンセプトメニュー"></p><p>コンセプトをアップロードするには、「<strong>コンセプトへの新しい参照を追加</strong>」ボタンをクリックします。</p><p>一度に1つまたは複数のコンセプトをアップロードできます。</p><p><img src="'+W+'" alt="コンセプトの空ページ"></p><p>プレビューをアップロードすると、コンセプトページは次のようになります。</p><p><img src="'+X+'" alt="コンセプトの入力ページ"></p><p>コンセプトとやりとりするには2つの方法があります。画像をクリックすると拡大表示されます。 もう1つはステータス部分をクリックして右側の<strong>コメントパネル</strong>を開く方法です。</p><p>コメントパネルでは、コンセプトを既存のアセットにリンクするか、削除するかの2つのオプションがあります。 また、アセットにコメントを追加したり、ステータスを変更することもできます。</p><p><strong>コンセプト</strong>ごとに1つのバージョンを持つことが基本です。承認されていない場合は、同じコンセプトの複数のバージョンを作成しないよう、新しいコンセプトをアップロードする必要があります。</p><p>1つのコンセプトは1つのタスクです。</p><p><img src="'+z+'" alt="コンセプトオプション"></p><h3 id="コンセプトとアセットのリンク" tabindex="-1">コンセプトとアセットのリンク <a class="header-anchor" href="#コンセプトとアセットのリンク" aria-label="Permalink to “コンセプトとアセットのリンク”">​</a></h3><p>コンセプトをアップロードすると、アセットにリンクすることができます。</p><p>アセットのステータス部分にリンクが表示されます。</p><p>コンセプトのステータス部分をクリックすると、右側にコメントパネルが開きます。</p><p><img src="'+Y+'" alt="コンセプトコメントパネル"></p><p>コメントパネルの上部には、コンセプトをアセットにリンクするか、コンセプトを削除するかの2つのオプションがあります。</p><p>アセットをリンクするには、[リンク] ボタン <img src="'+Z+'" alt="リンクボタン"> をクリックします。</p><p>Kitsu は、アップロードしたコンセプトにリンク可能なすべての <strong>アセット</strong> を表示します。</p><p>Kitsu は、コメントパネルの上部にリンクされたアセットをリスト表示します。現時点では、リンクはありません。</p><p><img src="'+pp+'" alt="コンセプトのリンク"></p><p>アセットをリンクするには、それをクリックする必要があります。リンクされたアセットの名前は画面の上部に表示され、コンセプトのプレビューの下にも表示されます。</p><p><img src="'+sp+'" alt="コンセプトのアセットがリンクされた状態"></p><p>コンセプトがアセットにリンクされると、アセットの詳細ページで確認できます。</p><p>アセットページに戻り、コンセプトを確認したいアセット名をクリックします。</p><p><img src="'+m+'" alt="アセット詳細ページ"></p><p>デフォルトでは、キャスティングの詳細が画面の2番目の部分に表示されます。 ドロップダウンメニューを使用してコンセプトを選択します。</p><p><img src="'+tp+'" alt="アセット詳細コンセプト"></p><p>コンセプトセクションに入ると、このアセット用に作成されたすべてのコンセプトが表示されます。ステータスごとにフィルタリングすることができます。</p><p><img src="'+rp+'" alt="アセット詳細コンセプトリスト"></p><h2 id="マップの作成" tabindex="-1">マップの作成 <a class="header-anchor" href="#マップの作成" aria-label="Permalink to “マップの作成”">​</a></h2><h3 id="最初のマップの作成" tabindex="-1">最初のマップの作成 <a class="header-anchor" href="#最初のマップの作成" aria-label="Permalink to “最初のマップの作成”">​</a></h3><p>いよいよ、<strong>マップ</strong>を作成する時が来ました。</p><p>::: 警告 マップは、Kitsu内のレベルにリンクされています。 つまり、まずレベルを作成し、次にこのレベルにマップを追加する必要があります。 :::</p><p><strong>マップ</strong>ページに移動する必要があります。 ドロップダウンメニューを使用して、<strong>mapS</strong>をクリックします。</p><p><img src="'+ap+'" alt="ドロップダウンメニューマップ"></p><p><strong>Add maps</strong>ボタンをクリックして、マップの作成を開始します。</p><p><img src="'+op+'" alt="最初にマップを追加"></p><p>::: 警告 マップを作成すると、設計したタスクワークフローが適用され、すべてのタスクがマップと同時に作成されます。 :::</p><p>マップの作成用に新しいポップアップが開きます。 これでレベルとマップを作成できます。</p><p>最初のレベル、例えば「sq01」を入力し、 次に<strong>追加</strong>します。</p><p>これで、レベルが作成されたことが確認できます。このレベルに追加するマップを選択し、作成します。</p><p>例えば、マップの列に「sh0010」と入力し、再度<strong>追加</strong>します。 マップのパディングを定義することもできます。</p><p>::: ヒント マップに SH0010、SH0020、SH0030 などのように 10 進法で名前を付けたい場合は、<strong>マップのパディング</strong>を 10 に設定します :::</p><p><img src="'+gp+'" alt="マップの管理"></p><p>新しいマップがリスト化され、レベル別にリンクされているのが確認できます。 最初のレベルの最初のマップを作成しました。</p><p>それでは、1つ以上のマップを追加してみましょう！ご覧の通り、ボックスにはすでにあなたの名前コードが 含まれていますが、インクリメントされています。そのため、<strong>追加</strong>をクリックして、 さらにマップを作成する必要があります。</p><p><img src="'+np+'" alt="マップの追加"></p><p>さらにレベルを追加するには、左側部分に移動し、新しいレベルの名前を入力して、<strong>追加</strong>をクリックします。 2番目のレベルが選択され、マップを追加できるようになります。</p><p>::: ヒント マップがレベルに正しく配置されていない場合は、マップを編集する必要があります ！<a href="../img/getting-started/edit_button.png">編集ボタン</a>をクリックし、 レベルを変更します。 ！<a href="../img/getting-started/edit_shot.png">マップの編集 レベルの変更</a></p><p>！<a href="../img/getting-started/change_seq.png">レベルの変更</a> :::</p><p>マップを削除するには、FAQを参照してください。 : マップの削除方法</p><p>レベルを削除するには、FAQを参照してください。 : レベルの削除方法</p><h2 id="edlファイルからマップを作成" tabindex="-1">EDLファイルからマップを作成 <a class="header-anchor" href="#edlファイルからマップを作成" aria-label="Permalink to “EDLファイルからマップを作成”">​</a></h2><p>すでに<strong>EDL</strong>ファイルにマップリストが用意されているかもしれません。 Kitsuでは、<strong>EDL</strong>ファイルを直接インポートして、レベル、マップ、複数のフレーム、フレームイン、フレームアウトを作成することができます。</p><p>グローバルマップページ<strong>では、</strong>インポートEDL**ボタンが表示されます。</p><p><img src="'+ip+'" alt="EDLインポートボタン"></p><p>ポップアップで、編集時に使用するビデオファイルの命名規則を選択できます。</p><p><img src="'+lp+'" alt="EDLインポートメニュー"></p><p>これは、プロジェクト_レベル_マップ.拡張子という名前で編集中のビデオクリップが命名されていることを意味します。</p><p>LGC制作のEDLの例を以下に示します。</p><p><img src="'+ep+'" alt="EDLの例"></p><p>動画ファイルの名前はLGC_100-000.movです。これは、LGCが制作名、100がレベル名、000がマップ名であることを意味します。</p><p>命名規則を設定したら、EDLファイルをインポートできます。</p><p>次に、<strong>[Upload EDL]</strong>をクリックします。</p><p>その後、Kitsuがマップを作成します。</p><p><img src="'+mp+'" alt="EDL map creation"> :::</p><p>::: 詳細 CSVスプレッドシートファイルからマップを作成 マップの一覧がすでにスプレッドシートファイルに用意されているかもしれません。 Kitsuでは、インポートする方法が2つあります。1つ目は、<code>.csv</code>ファイルを直接インポートする方法、2つ目は、データを直接Kitsuにコピー＆ペーストする方法です。</p><p>まず、スプレッドシートを<code>.csv</code>ファイルとして保存します。</p><p>次に、Kitsuのマップページに戻り、<strong>インポート</strong>アイコンをクリックします。 <img src="'+p+'" alt="インポートアイコン"></p><p>「CSVからデータをインポート」というポップアップウィンドウが開きます。「参照」をクリックして、<code>.csv</code>ファイルを選択します。</p><p><img src="'+hp+'" alt="インポートしたCSVファイル"></p><p>結果を確認するには、「プレビュー」ボタンをクリックします。</p><p>データのプレビューで、列の名前を確認し、調整することができます。</p><p>注：<strong>「チャプター」</strong>の列は、<strong>「テレビ番組」</strong>の制作の場合のみ必須です。</p><p><img src="'+_+'" alt="インポートデータのコピー＆ペースト"></p><p>すべてが適切であることを確認したら、<strong>「確認」</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべてのマップがKitsuにインポートされ、<strong>「設定」</strong>に従ってタスクが作成されます。</p><p><img src="'+t+'" alt="インポート データ コピー ペースト データ"> ::::</p><p>:::: 詳細 スプレッドシートファイルのコピー/ペーストによるマップの作成 スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+d+'" alt="インポート コピー データ"></p><p>次に、Kitsuのマップページに戻り、<strong>インポート</strong>アイコンをクリックします ！<a href="../img/getting-started/import.png">インポートアイコン</a>。</p><p>ポップアップウィンドウ<strong>インポートデータからCSV</strong>が開きます。<strong>CSVデータを貼り付け</strong>タブをクリックします。</p><p>！<a href="../img/getting-started/import_pastcsvdata_shot.png">インポートデータコピーペーストタブ</a></p><p>以前に選択したデータを貼り付け、<strong>[プレビュー]</strong> ボタンで結果を確認できます。</p><p><img src="'+u+'" alt="データのコピー＆ペースト"></p><p>データのプレビューで列の名前を確認し、調整できます。</p><p>注：<strong>[チャプター]</strong>列は、<strong>[テレビ番組]</strong>制作の場合のみ必須です。</p><p><img src="'+_+'" alt="インポートデータのコピー＆ペースト"></p><p>すべてが正しく入力されていることを確認したら、<strong>「Confirm」</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべてのマップがKitsuにインポートされ、<strong>「Settings」</strong>の設定に従ってタスクが作成されます。</p><p><img src="'+t+'" alt="インポートデータのコピー＆ペースト"> ::::</p><h3 id="マップの詳細を確認する" tabindex="-1">マップの詳細を確認する <a class="header-anchor" href="#マップの詳細を確認する" aria-label="Permalink to “マップの詳細を確認する”">​</a></h3><p>マップの詳細を確認したい場合は、マップ名をクリックします。</p><p><img src="'+cp+'" alt="map detail"></p><p>新しいページが開き、右側にタスク、割り当て、ステータスニュースフィードの一覧が表示されます。 タブ名をクリックすることで、各タブを切り替えることができます。</p><p><img src="'+_p+'" alt="map detail page"></p><p>各タスクのステータスをクリックすると、コメントパネルが開き、コメントの履歴や異なるバージョンを確認できます。</p><p><img src="'+dp+'" alt="map detail page"></p><p>また、<strong>キャスティング</strong>にもアクセスできます。</p><p><img src="'+up+'" alt="アセット詳細キャスティング"></p><p><strong>スケジュール</strong>は、タスクタイプページのデータを事前に記入している場合に利用できます。データがすでに記入されている場合は、ここで直接修正することができます。</p><p><img src="'+bp+'" alt="アセット詳細キャスティング"></p><p>各種タスクタイプでアップロードされた<strong>プレビューファイル</strong>、</p><p><img src="'+fp+'" alt="アセット詳細キャスティング"></p><p>そして、このアセットのタスクでタイムシートが記入された場合の<strong>タイムログ</strong>。</p><p><img src="'+kp+'" alt="アセット詳細キャスティング"></p><h2 id="マップ作成後にタスクを追加する" tabindex="-1">マップ作成後にタスクを追加する <a class="header-anchor" href="#マップ作成後にタスクを追加する" aria-label="Permalink to “マップ作成後にタスクを追加する”">​</a></h2><p>マップを作成した後でタスクが不足していることに気づいた場合でも、追加することができます。</p><p>まず、不足しているタスクタイプがタスクタイプタブの設定ページに追加されていることを確認します。</p><p>次にマップページに戻り、+タスクを追加をクリックします。</p><h3 id="マップを更新する" tabindex="-1">マップを更新する <a class="header-anchor" href="#マップを更新する" aria-label="Permalink to “マップを更新する”">​</a></h3><p>マップはいつでも更新でき、名前やレベルを変更したり、説明を修正したり、グローバルページに追加したカスタム情報を追加したりすることができます。</p><p>マップを編集するには、マップページに移動し、変更したいマップの上にカーソルを移動させてから、<strong>編集</strong>ボタンをクリックします ！<a href="../img/getting-started/edit_button.png">編集ボタン</a> (1) 行の右側にある。</p><p><img src="'+h+'" alt="アセットの編集"></p><p>メインのマップページの説明を拡張するには、最初の語句 (2) をクリックすると、説明の全文を含むポップアップが開きます。</p><p>::: 詳細 マップの更新 CSV インポート CSV インポート<strong>を使用して、</strong>NB フレーム<strong>、</strong>フレーム IN<strong>、</strong>フレーム OUT**、または任意のカスタム <strong>メタデータ コラム</strong> としてデータを更新することができます。</p><p>アサインメント<strong>、およびタスクの <strong>ステータス</strong> を更新し、</strong>コメント** を追加することができます。</p><p>スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+d+'" alt="インポートコピーデータ"></p><p>次に、Kitsuのマップページに戻り、<strong>インポート</strong>アイコンをクリックします <img src="'+p+'" alt="インポートアイコン">。</p><p>ポップアップウィンドウ<strong>インポートデータからCSV</strong>が開きます。<strong>CSVデータを貼り付け</strong>タブをクリックします。</p><p><img src="'+Kp+'" alt="インポートデータのコピー＆ペーストタブ"></p><p>以前に選択したデータを貼り付け、<strong>プレビュー</strong>ボタンで結果を確認できます。</p><p><img src="'+u+'" alt="インポートデータのコピー＆ペーストデータ"></p><p>オプション：既存のデータを更新** をオンにする必要があります。 更新されたマップは青くなります。</p><p>注：<strong>チャプター</strong>の列は、<strong>TV番組</strong>の制作の場合のみ必須です。</p><p><img src="'+xp+'" alt="データのインポート データのコピー＆ペースト"></p><p>すべてが正しく入力されたら、<strong>Confirm</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべてのマップがKitsuにインポートされ、<strong>設定</strong>に従ってタスクが作成されます。</p><p><img src="'+t+'" alt="インポートデータコピーペーストデータ"> :::</p><h2 id="マップにフレーム数とフレーム範囲を追加する" tabindex="-1">マップにフレーム数とフレーム範囲を追加する <a class="header-anchor" href="#マップにフレーム数とフレーム範囲を追加する" aria-label="Permalink to “マップにフレーム数とフレーム範囲を追加する”">​</a></h2><p>この段階では、アニマティックが完了しているはずです。つまり、 各マップのフレーム長（<strong>フレーム数</strong>、<strong>フレーム範囲イン</strong>、<strong>フレーム範囲アウト</strong>）が分かっているはずです。 この情報をスプレッドシートに追加できます。この方法により、 すべてのフレームが計算され、抜けや過剰計算がないことを確認できます。</p><p>::: 警告 マップとレベルを手動で作成した場合、 <strong>フレーム</strong>列は非表示になります。<strong>フレーム</strong>列を表示するには、少なくとも1つのマップを編集してフレーム数を入力する必要があります。 マップを手動で作成せずに、CSV/スプレッドシートでフレーム数をインポートした場合は、列が表示されます。 :::</p><p>マップを編集してフレーム範囲の情報を入力する必要があります。 編集ボタンをクリックしてください！<a href="../img/getting-started/edit_button.png">編集ボタン</a> マップ行の右側にある</p><p>！<a href="../img/getting-started/edit_shot.png">編集マップ レベル変更</a></p><p>新しいウィンドウで、マップの<strong>イン</strong>と<strong>アウト</strong>を入力できます。次に、<strong>確認</strong>ボタンをクリックして保存します。</p><p><img src="'+Sp+'" alt="map edit page"></p><p>これで、フレーム範囲がマップページの一般的なスプレッドシートに表示されます。</p><p><img src="'+Pp+'" alt="map edit page"></p><p><strong>Frames</strong>、<strong>In</strong>、および<strong>Out</strong>列のロックを解除したので、 グローバルマップページから直接入力することができます。</p><p>入力したいケースをクリックしてデータを追加します。</p><p>::: ヒント フレームイン<strong>と</strong>フレームアウト<strong>を入力すると、Kitsuは自動的に</strong>フレーム数**を計算します。 :::</p><p><img src="'+Cp+'" alt="マップ編集ページ"></p><p><strong>CSVインポート</strong>を使用してフレーム範囲を素早く更新することもできます。 CSVインポートでマップ情報を更新</p><p>マップ値の履歴にもアクセスできます。</p><p><img src="'+Vp+'" alt="マップ フレーム範囲の詳細"></p><p><img src="'+vp+'" alt="マップ値の履歴"></p><h2 id="カスタムメタデータカラムの作成" tabindex="-1">カスタムメタデータカラムの作成 <a class="header-anchor" href="#カスタムメタデータカラムの作成" aria-label="Permalink to “カスタムメタデータカラムの作成”">​</a></h2><p>一般的なスプレッドシートページにさらに情報を追加するには、カスタム<strong>メタデータカラム</strong>を作成する必要があります。</p><p>難易度<strong>、</strong>天気<strong>、</strong>タグ**など、ページに追加する追加情報があるかもしれません。すべてのテキスト（または数値）情報をカスタムメタデータ列に保存できます。</p><p>名前列の近くにある<strong>+</strong>をクリックします。</p><p><img src="'+g+'" alt="メタデータ列"></p><p>タイプ**オプションでは、情報をどのように保存するかを選択できます。</p><ul><li>自由入力の<strong>テキスト</strong>、</li><li><strong>数値</strong>、</li><li><strong>チェックボックス</strong>、</li><li><strong>値のリスト</strong>、</li><li><strong>タグのリスト</strong>、</li><li><strong>チェックリスト</strong>。</li></ul><p><img src="'+Dp+'" alt="メタデータカラムの詳細"></p><p>::: 警告 テキスト<strong>、</strong>数値<strong>、および</strong>チェックボックス**では、エンティティごとに異なる情報を追加できます。事前に計画しておく必要はありません。</p><p>リスト<strong>、</strong>タグ<strong>、および</strong>チェックリスト**では、エンティティごとに同じ選択肢が提供されます。さらに、これは現在入力する必要があります。</p><p><img src="'+Ep+'" alt="メタデータカラムリスト"></p><p>利用可能な値<strong>の下にリスト要素を入力し、</strong>値を追加**をクリックして確認します。 :::</p><p>メタデータカラム<strong>を1つまたは複数の</strong>部門**にリンクすることもできます。</p><p>::: ヒント メタデータカラムを部門にリンクします。アーティスト/スーパーバイザーは、自分のToDoページと部門フィルタリングビューでこれを見ることができます。</p><p>メタデータカラムを1つまたは複数の部門にリンクすることができます。リストから部門をクリックし、<strong>追加</strong>をクリックして有効にします。</p><p>ここでは、VFXカラムが2つの部門にリンクされています。</p><p><img src="'+Lp+'" alt="部門メタデータカラムのフィルタ表示"></p><p>:::</p><p>::: 詳細 メタカラムの編集 アセットのグローバルページまたはマップで、メタカラムの右側にある矢印をクリックし、<strong>[編集]</strong>をクリックします。</p><p><img src="'+wp+'" alt="メタカラムの編集"> :::</p><p>この情報は、グローバルスプレッドシートページで直接入力できます。 ケースは編集可能です。</p><p><img src="'+Ap+'" alt="メタデータ列の詳細"></p><p>::: ヒント 左側の複数のエンティティを選択し、メタデータ列を一括で変更することができます。 :::</p><p>::: 詳細 手動で編集 編集ボタン <img src="'+Tp+'" alt="編集ボタン"> を使用して情報を変更することもできます。</p><p>編集ポップアップに新しい行が表示されます。リストから情報を選択することもできますが、 代わりに、テキストや数値を直接入力したり、チェックボックスにチェックを入れたり、チェックリストを使用したりすることもできます。</p><p>編集が完了したら、必ず「確認」ボタンをクリックしてください。</p><p><img src="'+Bp+'" alt="メタデータカラムの詳細"> :::</p><p>メタデータ列を編集または削除する場合は、スプレッドシートの一般ページに移動します。 メタデータ列の名前の近くにある矢印をクリックします！<a href="../img/getting-started/arrow.png">メタデータ列の詳細</a>。</p><p>::: ヒント この新しい列を使用して、グローバルページを<strong>ソート</strong>することができます。列名の右にある矢印をクリックして、このメニューを開きます。次に、<strong>ソート</strong>をクリックします。</p><p>メタデータ列を左側に<strong>固定</strong>することもできます。 :::</p><h2 id="レベルを作成" tabindex="-1">レベルを作成 <a class="header-anchor" href="#レベルを作成" aria-label="Permalink to “レベルを作成”">​</a></h2><p>Kitsuでは、<strong>レベル</strong>レベルでタスクを追跡することもできます。 これは、 ストーリーやカラーボード、カラーグレーディングなど、マクロタスクを追跡する際に特に便利です。</p><p>ナビゲーションメニューを使用して、<strong>レベル</strong>ページに移動します。</p><p><img src="'+Fp+'" alt="Navigation levels"></p><p>::: 警告 この新しいページは、アセットおよびマップのグローバルページと同様に動作します。</p><p>このページを使用するには、まず<strong>グローバルライブラリ</strong>に<strong>レベル</strong>属性を持つ専用のタスクタイプを作成する必要があります。</p><p>新しい <strong>タスクタイプ</strong> を作成するには、<strong>新しいタスクタイプの作成</strong> セクションを参照してください。</p><p><a href="./../configure-kitsu/#タスクの種類">新しいタスクタイプの作成</a></p><p>グローバルライブラリに<strong>タスクタイプ</strong>を作成したら、それを** プロダクションライブラリ**（設定ページ）に追加します。 :::</p><p>設定ページでタスクタイプが準備できたら、レベル（アセットやマップと同じ）を作成する必要があります。</p><p>この新しいページは、アセットやマップのグローバルページと同様に動作します。<strong>+ 新しいレベル</strong>ボタンで編集を追加できます。</p><p>タスクの割り当て、レビュー、ステータスの変更などを行うことができます。</p><p>メタデータ列の追加、説明の記入などを行うことができます。</p><p>::: ヒント ここ（+新しいレベルボタン）から直接レベルを作成するか、グローバルマップページからマップにリンクされたレベルを作成することができます。 :::</p><p>このページでは、レベルのエンティティを<strong>名前変更</strong>したり、<strong>削除</strong>したりすることができます。また、アセットやマップのエンティティも同様です。</p><p>レベルの名前をクリックすると、そのレベルの詳細ページが表示されます。</p><p><img src="'+Np+'" alt="レベルの詳細ページ"></p><p>詳細ページでは、レベルのキャスティングにアクセスできます。 レベル全体で使用されたすべてのアセットを確認できます。</p><p>また、レベルの<strong>タスク</strong>のスケジュール、プレビューファイル、アクティビティ、タイムログにもアクセスできます。</p><h2 id="作成と編集" tabindex="-1">作成と編集 <a class="header-anchor" href="#作成と編集" aria-label="Permalink to “作成と編集”">​</a></h2><p>Kitsuでは、<strong>編集</strong>レベルでタスクを追跡できます。</p><p>特に、 複数の検証ステップで複数の編集を追跡する必要がある場合に便利です。例えば、映画全体、いくつかの予告編、ファースト・エディット、ファイナル・エディット、ミックスなどを追跡できます。</p><p>::: 警告 デフォルトでは、<strong>Edit</strong> ページは、<strong>production library</strong> (設定ページ) にタスクタイプが設定されるまで表示されません :::</p><p>このページを使用するには、まず <strong>Global Library</strong> に <strong>Edit</strong> 属性を持つ専用のタスクタイプを作成する必要があります。</p><p>新しい <strong>タスクタイプ</strong> を作成するには、<strong>新しいタスクタイプの作成</strong> セクションを参照してください。</p><p><a href="./../configure-kitsu/#タスクの種類">新しいタスクタイプの作成</a></p><p><strong>グローバルライブラリ</strong>に<strong>タスクタイプ</strong>を作成したら、<strong>プロダクションライブラリ</strong>に追加します。 すると、ナビゲーションのドロップダウンメニューに「<strong>編集</strong>」が表示されます。</p><p><img src="'+Ip+'" alt="ナビゲーション編集"></p><p>この新しいページは、アセットやマップのグローバルページと同様に動作します。<strong>+ 新規編集</strong> ボタンで編集を追加できます。</p><p>タスクの割り当て、レビュー、ステータスの変更などを行うことができます。</p><p>メタデータ列を追加したり、説明を記入したりすることができます。</p><p>::: ヒント 配信内容に応じて、<strong>[編集]</strong> ごとの解像度を変更することもできます。 :::</p><p>::: 警告 詳細ページは、他のエンティティとは異なります。</p><p><strong>[編集]</strong> は特定のロングビデオに焦点を当てているため、詳細ページはコメントの詳細ページにより似たものとなっています。 :::</p><p>このページでは、アセットやマップのエンティティと同様に、<strong>[編集]</strong> エンティティの <strong>[名前の変更]</strong> や <strong>[削除]</strong> を行うことができます。</p><h2 id="ブレークダウンリストの作成" tabindex="-1">ブレークダウンリストの作成 <a class="header-anchor" href="#ブレークダウンリストの作成" aria-label="Permalink to “ブレークダウンリストの作成”">​</a></h2><p>ブレークダウンを記入すると、マップの組み立てに役立ちます。 ブレークダウンには、マップを作成するために追加する必要のあるアセットの詳細がすべて記載されています。 これにより、何も漏れなく確実に作業を進めることができます。</p><p>ドロップダウンメニューで <strong>BREAKDOWN</strong> を選択します。</p><p><img src="'+Op+'" alt="drop down Menu breakdown"></p><p>ブレイクダウンページの左側には、チャプター/レベル/マップメニュー（1）があります。作成したものの中から選択できます。これらは画面の右側部分であり、 作成したすべてのアセットは、この制作（メインパックおよびチャプター）で利用可能です（3）。さらに、 中央セクションでは、マップ（2）を選択します。</p><p><img src="'+yp+'" alt="ブレイクダウンページ"></p><p>では、次に、配置するマップを選択する必要があります。</p><p>サムネイルがまだない場合はアセットをテキストで表示したり、 サムネイルのサイズを拡大することができます。</p><p><img src="'+Gp+'" alt="ブレークダウンページのテキスト表示"></p><p>また、ブレークダウン中にリストにアセットを追加する必要があることに気づくかもしれません。</p><p>ブレークダウンページから直接新しいアセットを作成することができます。「利用可能なすべてのアセット」の右にある「+」をクリックします。</p><p><img src="'+Hp+'" alt="ブレークダウンページのアセット作成"></p><p>複数のマップを一度に選択することもできます。最初のマップをクリックし、「シフト」キーを押したまま、選択する最後のマップをクリックします。</p><p><img src="'+Mp+'" alt="Breakdown page global bulk select"></p><p>次に、割り当てたいアセットをクリックします。 キャラクター、背景など、右側部分（3）から選択します。 複数のマップを選択した場合、選択した内容は多数のマップに適用されます。</p><p>アセットが入力されたマップをコピーし、このアセット選択を別のマップに貼り付けます。</p><p>アセットの上にカーソルを移動させると、<strong>+1</strong> または <strong>+10</strong> と表示されます。これは、 そのアセットを追加した回数を表します。必要なだけクリックできます。</p><p><img src="'+Qp+'" alt="ブレイクダウンにアセットを追加"></p><p>レベルやマップを指定せずに、すべてのアセットをテレビ番組のチャプターにリンクすることもできます。</p><p><img src="'+Rp+'" alt="Breakdown chapter asset"></p><p>この方法では、ストーリーボード/アニマティックの段階の前に、すべてのアセットを1つまたは複数のチャプターにリンクすることができます。</p><p>画面の中央にアセットが表示されているのが確認できます（2）。 アセット名の隣には、追加された回数が表示されています。この 例では、キャラクターアセット「Llama」を2回追加しています。</p><p>誤ってアセットを2回追加してしまった場合は、画面の中央部分でこのマップのアセットを選択する必要があります（2）。そこから、<strong>-1</strong>をクリックします。 このマップの作業が完了したら、他のマップの作業を進めてください。 選択した内容は自動的に保存されます。</p><p><img src="'+$p+'" alt="Breakdown remove asset"></p><p>ストーリーボードの作成中に新しいアセットが作成された場合は、アセットページに戻り （ドロップダウンメニューを使用）、必要なアセットを作成します。以前に作成したタスクは、これらの新しいアセットに即座に適用されます。 ただし、割り当てを行う必要があり、その後、 ブレークダウンを継続できます。</p><p>これで、<strong>Breakdown</strong>ページは以下のようになります。</p><p><img src="'+r+'" alt="breakdown add asset bulk"></p><p>アセットを組み立てて個々のパーツを追跡する必要がある場合は、アセットのブレークダウンリストを作成することもできます。</p><p>画面左上にある<strong>FOR</strong>の下のドロップダウンメニューで<strong>asset</strong>を選択します。</p><p><img src="'+jp+'" alt="アセットの分類メニュー"></p><p>次に、2番目のドロップダウンメニューにアクセスして、アセットの種類を選択します。キャラクター、環境、小道具、特殊効果など</p><p><img src="'+qp+'" alt="アセットタイプの分類"></p><p>アセットの分類ページは、マップと同様の方法で作成できます。まず、左側の部分で1つまたは複数のアセットを選択し、次に右側の部分の要素を追加します。</p><p>::: 詳細 CSVファイルからブレークダウンリストを作成する</p><p>すでにスプレッドシートファイルに内訳リストが用意されているかもしれません。Kitsuでは、それをインポートする方法が2つあります。1つ目は、.csvファイルを直接インポートする方法、2つ目は、データを直接Kitsuにコピー＆ペーストする方法です。</p><p>まず、Kitsuの推奨に従って、スプレッドシートを「.csv」ファイルとして保存します。</p><p>インポート]ボタンをクリックします！[インポート]ボタン（../img/getting-started/import.png）</p><p>「CSVからデータをインポート」というポップアップウィンドウが開きます。「参照」をクリックして、<code>.csv</code>ファイルを選択します。</p><p><img src="'+b+'" alt="インポートしたCSVファイルの分割"></p><p>結果を確認するには、「プレビュー」ボタンをクリックします。</p><p>データのプレビューで列の名前を確認し、調整することができます。</p><p>注：<strong>「チャプター」</strong>列は、<strong>「テレビ番組」</strong>制作の場合のみ必須です。</p><p><img src="'+a+'" alt="Breakdown import Preview"></p><p>すべてが適切であることを確認したら、<strong>「Confirm」</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、ブレークダウンがKitsuにインポートされました。</p><p><img src="'+r+'" alt="ブレークダウンインポートプレビュー"> :::</p><p>::: 詳細 スプレッドシートファイルをコピー＆ペーストしてブレークダウンリストを作成</p><p>スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+Up+'" alt="インポートコピーデータ"></p><p>次に、Kitsuのブレークダウンページに戻り、<strong>インポート</strong>アイコンをクリックします <img src="'+p+'" alt="インポートアイコン">。</p><p>ポップアップウィンドウ「<strong>CSVからデータをインポート</strong>」が開きますので、「<strong>CSVデータを貼り付け</strong>」タブをクリックします。</p><p><img src="'+b+'" alt="インポートデータコピーペーストタブ"></p><p>以前に選択したデータを貼り付け、<strong>[プレビュー]</strong>ボタンで結果を確認できます。</p><p><img src="'+a+'" alt="データのコピー＆ペースト"></p><p>データのプレビューで列の名前を確認し、調整できます。</p><p>注：<strong>[チャプター]</strong>列は、<strong>[テレビ番組]</strong>制作の場合のみ必須です。</p><p><img src="'+a+'" alt="インポートデータのコピー＆ペースト"></p><p>すべてが正しく入力されたら、<strong>Confirm</strong>（確認）ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべてのアセットがKitsuにインポートされました。</p><p><img src="'+r+'" alt="インポートデータのコピー＆ペースト"> :::</p><h2 id="アセットの状態の紹介-使用可能" tabindex="-1">アセットの状態の紹介：使用可能 <a class="header-anchor" href="#アセットの状態の紹介-使用可能" aria-label="Permalink to “アセットの状態の紹介：使用可能”">​</a></h2><p>ほとんどの場合、アセットのタスクが承認されるのを待たなくても、マップタスクで使用することができます。</p><p>例えば、アセットが<strong>コンセプト</strong>段階で承認された場合、<strong>ストーリーボード</strong>段階で使用することができます。 次に、<strong>モデリング</strong>段階で承認された場合、<strong>レイアウト</strong>段階で使用することができます。</p><p>まさにアセットの状態「<strong>準備完了</strong>」がやっていることです。アセットのタスクの状態を知らせ、マップタスクでの使用可能性を比較します。</p><p>ブレークダウンを記入したので、どのアセットがすべてのマップで使用されているかが正確にわかります。</p><p>まず、タスクの状態と関連するアセットの状態を定義する必要があります。セルをクリックして<strong>準備完了</strong>を変更することができます。マップタスクのドロップダウンメニューが表示されます。</p><p><img src="'+Jp+'" alt="アセットの状態"></p><p>::: ヒント <strong>自動化</strong>を使用して、重労働を軽減することができます。</p><p><strong>準備完了</strong>トリガーで自動化を設定できます。 :::</p><p>アセットの状態をいくつか<strong>準備完了</strong>に変更したので、マップページで結果を確認できます。</p><p>いくつかの白いボックスが<strong>緑色</strong>になっていることに気づくでしょう。このマップ内のすべてのアセットが、この特定のタスクの準備ができていることを示しています。</p><p><img src="'+Wp+'" alt="アセットの状態"></p><p>白いボックスが表示されている場合、Kitsuは、このタスクに何個のアセットが準備されているかを示します。</p><p><img src="'+Xp+'" alt="Asset Status"></p><p>::: ヒント ボックスが表示されていない場合、このマップにはアセットがキャストされていません。 :::</p><p>次に、マップの名前をクリックして詳細ページに移動します。 すると、このマップにキャストされたすべてのアセットとそのステータスが表示されます。</p><p><img src="'+zp+'" alt="アセットステータス"></p><p>特定のタスク用のマップを開始できるかどうかを判断する最も簡単な方法です。</p>',469)])])}const ns=f(Yp,[["render",Zp]]);export{gs as __pageData,ns as default};
